# Advanced text formatters module
# Extends base text utilities with formatting capabilities

from text_utils import TextProcessor, clean_text

class TitleFormatter(TextProcessor):
    prefix: str

    def __init__(self, text: str, prefix: str = ""):
        super().__init__(text)
        self.prefix = prefix

    @override
    def process(self) -> str:
        base: str = super().process()
        return self.prefix + base.title()

class Truncator(TextProcessor):
    max_length: int

    def __init__(self, text: str, max_length: int):
        super().__init__(text)
        self.max_length = max_length

    @override
    def process(self) -> str:
        s: str = super().process()
        if len(s) > self.max_length:
            return s[:self.max_length] + "..."
        return s

    @override
    def get_stats(self) -> dict[str, int]:
        base_stats: dict[str, int] = super().get_stats()
        base_stats["truncated"] = len(self.process())
        return base_stats

def format_report(data: list[str]) -> str:
    lines: list[str] = []
    for i, item in enumerate(data):
        lines.append(f"{{i + 1}}. {{clean_text(item)}}")
    return "\n".join(lines)
